import React, { useState, useEffect } from 'react';
import { useApp } from '../context/AppContext';
import bs58 from 'bs58';

export default function WalletsPage() {
  const { 
    wallets, 
    balances,
    addWallet, 
    importWallet, 
    removeWallet, 
    addLog,
    refreshWalletBalances,
    connection
  } = useApp();

  const [importKey, setImportKey] = useState('');
  const [showSecret, setShowSecret] = useState({});

  // Auto-refresh on mount
  useEffect(() => {
    if (wallets.length > 0) {
      refreshWalletBalances();
    }
  }, []); // Run once on mount

  const createWallet = async () => {
    const wallet = await addWallet();
    if (wallet) {
      addLog('Created: ' + wallet.publicKey.slice(0, 20) + '...', 'success');
    }
  };

  const handleImportWallet = async () => {
    try {
      let secretKey;
      try {
        secretKey = bs58.decode(importKey);
      } catch {
        secretKey = new Uint8Array(JSON.parse(importKey));
      }

      const wallet = await importWallet(null, secretKey);
      if (wallet) {
        setImportKey('');
        addLog('Imported: ' + wallet.publicKey.slice(0, 20) + '...', 'success');
      }
    } catch (err) {
      addLog('Import failed: ' + err.message, 'error');
      alert('Invalid private key format');
    }
  };

  const exportWallet = (index) => {
    const wallet = wallets[index];
    const base58 = bs58.encode(wallet.keypair.secretKey);
    alert('Wallet: ' + wallet.publicKey + '\\n\\nPrivate Key (Base58):\\n' + base58);
  };

  const toggleSecret = (index) => {
    setShowSecret({ ...showSecret, [index]: !showSecret[index] });
  };

  const handleRemoveWallet = (publicKey) => {
    if (window.confirm('Remove this wallet?')) {
      removeWallet(publicKey);
    }
  };

  const formatBalance = (publicKey) => {
    const bal = balances[publicKey];
    if (bal === undefined) return 'Click Refresh';
    if (bal === 0) return '0 SOL';
    return bal.toFixed(4) + ' SOL';
  };

  return (
    <div>
      <div className="glass-panel">
        <div className="section-label">// CREATE WALLET</div>
        <button className="btn-primary" onClick={createWallet}>
          Generate New Wallet
        </button>
      </div>

      <div className="glass-panel">
        <div className="section-label">// IMPORT WALLET</div>
        <textarea
          value={importKey}
          onChange={e => setImportKey(e.target.value)}
          placeholder="Private key (Base58 or JSON)..."
          style={{ minHeight: '60px', marginBottom: '12px', width: '100%' }}
        />
        <button className="btn-secondary" onClick={handleImportWallet}>
          Import
        </button>
      </div>

      <div className="glass-panel">
        <div className="section-label">// WALLETS ({wallets.length})</div>

        {connection && (
          <button 
            onClick={refreshWalletBalances}
            style={{ marginBottom: '16px', fontSize: '12px' }}
          >
            Refresh Balances
          </button>
        )}

        {wallets.length === 0 ? (
          <p style={{ color: '#666', fontSize: '12px' }}>No wallets yet.</p>
        ) : (
          wallets.map((wallet, index) => (
            <div key={wallet.publicKey} style={{ 
              marginBottom: '16px', 
              padding: '12px', 
              background: 'rgba(0,0,0,0.3)', 
              borderRadius: '8px',
              border: '1px solid rgba(0, 243, 255, 0.2)'
            }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '8px' }}>
                <strong>{wallet.name}</strong>
                <div>
                  <button style={{ fontSize: '10px', marginRight: '4px' }} onClick={() => toggleSecret(index)}>
                    {showSecret[index] ? 'Hide' : 'Show'}
                  </button>
                  <button style={{ fontSize: '10px', marginRight: '4px' }} onClick={() => exportWallet(index)}>
                    Export
                  </button>
                  <button style={{ fontSize: '10px', color: '#ff4444' }} onClick={() => handleRemoveWallet(wallet.publicKey)}>
                    Remove
                  </button>
                </div>
              </div>

              <div style={{ fontSize: '11px', color: '#00f3ff', marginBottom: '8px', wordBreak: 'break-all' }}>
                {wallet.publicKey}
              </div>

              {/* BALANCE DISPLAY */}
              <div style={{ 
                background: 'rgba(0, 243, 255, 0.1)',
                padding: '8px 12px',
                borderRadius: '6px',
                display: 'flex',
                justifyContent: 'space-between',
                alignItems: 'center'
              }}>
                <span style={{ fontSize: '11px', color: '#666' }}>Balance:</span>
                <span style={{ 
                  fontSize: '14px', 
                  fontWeight: 'bold',
                  color: balances[wallet.publicKey] > 0 ? '#00ff00' : '#00f3ff'
                }}>
                  {formatBalance(wallet.publicKey)}
                </span>
              </div>

              {showSecret[index] && (
                <div style={{ 
                  marginTop: '12px', 
                  padding: '10px', 
                  background: 'rgba(255, 170, 0, 0.1)', 
                  border: '1px solid #ffaa00',
                  borderRadius: '6px',
                  fontSize: '10px',
                  wordBreak: 'break-all',
                  color: '#ffaa00'
                }}>
                  <strong>SECRET KEY:</strong><br/>
                  {bs58.encode(wallet.keypair.secretKey)}
                </div>
              )}
            </div>
          ))
        )}
      </div>
    </div>
  );
}
